
CREATE TABLE public.knowledge_documents (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  title text NOT NULL,
  category text NOT NULL,
  content text NOT NULL,
  source text NOT NULL,
  created_at timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.knowledge_documents ENABLE ROW LEVEL SECURITY;

-- Counselors can manage knowledge documents
CREATE POLICY "Counselors can manage knowledge documents"
ON public.knowledge_documents
FOR ALL
TO authenticated
USING (has_role(auth.uid(), 'counselor'::app_role))
WITH CHECK (has_role(auth.uid(), 'counselor'::app_role));

-- Edge functions can read knowledge documents (via service role, no RLS needed for that)
-- But we also need anon to read for the AI analysis
GRANT SELECT ON public.knowledge_documents TO anon;
GRANT ALL ON public.knowledge_documents TO authenticated;

-- Insert knowledge base content from the parsed documents
INSERT INTO public.knowledge_documents (title, category, content, source) VALUES

-- التدخلات التربوية (Educational Interventions)
('التدخلات التربوية - المقدمة والأهداف', 'أكاديمية', 
'دليل التدخلات التربوية يهدف إلى مساعدة الموجهين الطلابيين في أداء مهمتهم عند التعامل مع حالات الطلاب الذين يواجهون خطر الوقوع في المشكلات أو من يعانون منها فعلاً. يتضمن الدليل فنيات معرفية سلوكية، دافعية وسلوك إنجاز، مذاكرة، اختبارات، مهارات اجتماعية، ومهارات التعامل مع الطلبة متكرري الغياب والتأخر الصباحي. أهداف الدليل: تقديم الخدمة التوجيهية بمهنية في مستوياتها الإنمائية والوقائية والعلاجية، رفع مستوى الوعي عند المعلمين والطلاب وأسرهم، تعزيز نواتج التعلم لدى الطلاب.', 'دليل التدخلات التربوية - وزارة التعليم 1445هـ'),

('أعراض وأسباب المشكلات التربوية', 'أكاديمية',
'الأعراض التربوية: انخفاض مستوى الدافعية للتعليم، الغياب الجزئي أو الكلي عن المدرسة، التأخر الصباحي، ضعف المشاركة في الأنشطة المدرسية، ظهور صعوبات التعلم ومشكلات التحصيل، الإهمال في أداء الواجبات المنزلية، عدم الانضباط داخل الفصل. الأسباب: البيئة المدرسية غير المهيأة، تأرجح النظام المدرسي بين الصرامة والقسوة، تدني مستوى التحصيل الدراسي، ضعف مراعاة المعلم للفروق الفردية، كثرة التكليفات والواجبات المنزلية.', 'دليل التدخلات التربوية - وزارة التعليم 1445هـ'),

('الفنيات المعرفية السلوكية والدافعية', 'أكاديمية',
'الفنيات المعرفية السلوكية تشمل: إعادة البناء المعرفي، حل المشكلات، التعلم الذاتي. الدافعية وسلوك الإنجاز: تحديد الأهداف، قصص النجاح والإلهام والسير الذاتية، التعزيز، إجراءات توظيف الدافعية في التعليم، التغذية الراجعة. المذاكرة: تهيئة المناخ الدراسي، محددات الاستذكار، تنظيم الوقت، جدول المذاكرة، مهارات القراءة وتنظيم الاستماع والتركيز وتدوين الملاحظات والتلخيص والمراجعة. طرق المذاكرة: طريقة SQ4R، خرائط العقل، خرائط المفاهيم. الاختبارات: مهارة الاستعداد للاختبارات، مهارة أداء الاختبارات، مهارة التخلص من قلق الاختبار.', 'دليل التدخلات التربوية - وزارة التعليم 1445هـ'),

-- التنمر (Bullying)
('التنمر المدرسي - التعريف والتصنيفات', 'سلوكية',
'التنمر المدرسي هو استهداف طالب أو مجموعة من الطلاب لطالب معين بصورة متكررة باستخدام أساليب غير مرغوبة ذات طبيعة نفسية أو بدنية تلحق الأذى بالطالب المستهدف. محددات التنمر: أن يكون المتنمر والمتنمر عليه من نفس الفئة العمرية (أقران)، أن تكون القوة الجسدية غير متكافئة (قوي-ضعيف)، استمرار التنمر لمدة من الزمن، تعمد الإضرار بالمتنمر عليه. تصنيفات التنمر: الجسدي (استخدام القوة الجسدية)، اللفظي (استخدام الألفاظ السيئة)، الاجتماعي (عزل المتنمر عليه عن الآخرين)، المادي (تخريب أو سرقة الأدوات)، الإلكتروني (استغلال التكنولوجيا والإنترنت للإيذاء).', 'دليل توعوي للحد من التنمر - وزارة التعليم 1446هـ'),

('مؤشرات حدوث التنمر', 'سلوكية',
'مؤشرات اجتماعية: فقدان الاهتمام بالأنشطة المعتادة، تغير مجتمع الأصدقاء، عدم الرغبة في الخروج من المنزل، العزلة داخل المنزل. مؤشرات جسدية: وجود آثار ضرب، آثار تلف على الملابس، عنف غير معهود تجاه الآخرين. مؤشرات صحية: الإجهاد العام وانخفاض الأداء، ضعف مقاومة العدوى، قلة الشهية أو المبالغة في الأكل، الأمراض المتكررة. مؤشرات نفسية: القلق والتوتر المستمر، الشعور بالوحدة والاكتئاب، اضطراب في النوم، الرغبة في البكاء، تقلب في المزاج. مؤشرات مدرسية: عدم الرغبة في الذهاب إلى المدرسة، الخوف من ركوب حافلة المدرسة، انخفاض مفاجئ في المستوى التحصيلي، تكرار الغياب عن المدرسة.', 'دليل توعوي للحد من التنمر - وزارة التعليم 1446هـ'),

('أدوار مواجهة التنمر', 'سلوكية',
'دور إدارة المدرسة: الإشراف على تنفيذ برامج التوجيه الطلابي الداعمة لمناهضة التنمر، متابعة الإشراف اليومي، نشر ثقافة استنكار التنمر المدرسي والإلكتروني، حث الطلبة على إبلاغ المدرسة فوراً عند رؤية موقف تنمري، تطبيق قواعد السلوك والمواظبة. دور المعلم: تعزيز السلوكيات الإيجابية داخل الفصل بالتشجيع والكلمات المحفزة، استثمار المناهج الدراسية لنشر قيم التسامح والإيجابية، ملاحظة سلوك الطلبة داخل الفصل. دور الموجه الطلابي مع المتنمر عليه: بناء علاقة إرشادية مهنية، تشجيع الطالب على الحديث والإنصات له، تدريب الطالب على مهارة تأكيد الذات، مساعدة الطالب على التخلص من مشاعر القلق والإحباط. دور الأسرة: تربية الأبناء على الحب والحوار والتقبل، البعد عن أساليب العنف في المنزل، تشجيع الأبناء على التحدث والإبلاغ عن حالات التنمر.', 'دليل توعوي للحد من التنمر - وزارة التعليم 1446هـ'),

-- خفض العنف (Violence Reduction - Rifq Program)
('برنامج خفض العنف (رفق) - الأهداف والأهمية', 'سلوكية',
'برنامج رفق لخفض العنف المدرسي بكافة أشكاله في جميع المراحل الدراسية. أهداف البرنامج: التأكيد على تعاليم الشريعة الإسلامية الداعية إلى التعامل مع الآخرين بالحسنى والتسامح والرحمة والعفو، تبصير العاملين في المدرسة وأولياء الأمور بمفهوم العنف وأسبابه وأشكاله المختلفة، تهيئة البيئة التربوية والأسرية المناسبة للطلبة، إكساب العاملين بالمدرسة وأولياء الأمور الأساليب التربوية الملائمة (الوقائية) لخفض العنف والتعامل معه، تزويد العاملين في التوجيه الطلابي بأساليب التدخل المبكر والعلاج في التعامل مع حالات العنف، إكساب الطلبة المهارات الشخصية والاجتماعية لخفض جميع أشكال العنف المدرسي.', 'برنامج خفض العنف (رفق) - وزارة التعليم 1445هـ'),

('العنف والتنمر - التعريفات والأنواع', 'سلوكية',
'العنف: كل سلوك متعمد ينتج عنه أضراراً جسدية أو نفسية للآخرين أو تخريبية للممتلكات. التنمر: شكل من أشكال العنف وهو عنف متعمد متكرر (ليس عابر) من فرد أو مجموعة ينتج عنه الإضرار الجسدي أو النفسي أو المادي أو الاجتماعي بفرد أو مجموعة من نفس العمر. الإيذاء: شكل من أشكال الاستغلال أو إساءة المعاملة الجسمية أو النفسية أو الجنسية أو التهديد، يرتكبه شخص تجاه آخر. أنواع العنف: جسدي (ضرب، ركل)، لفظي (سب، شتم)، نفسي (تهديد، إذلال)، اجتماعي (عزل، نبذ)، إلكتروني. أسباب العنف: عوامل بيولوجية، سلوكية (مكتسبة عبر التعزيز)، تعلم بالمشاهدة (النمذجة)، الإحباط، عوامل أسرية ومدرسية ومجتمعية.', 'برنامج خفض العنف (رفق) - وزارة التعليم 1445هـ'),

-- تعزيز السلوك الإيجابي (Positive Behavior)
('برنامج تعزيز السلوك الإيجابي', 'سلوكية',
'برنامج تعزيز السلوك الإيجابي هو برنامج يُعنى بدعم السلوك الإيجابي وتنميته من خلال بيئة محفزة وجاذبة، ترتكز على استخدام أساليب علمية لتعزيز السلوك الإيجابي لتحقيق التوافق النفسي والاجتماعي والتربوي للطالب. الأهداف: نشر وتعزيز السلوك الإيجابي لدى الطلبة بأساليب علمية، تنمية قدرات ومهارات مرشدي الطلاب ومنسوبي المدرسة لتنفيذ أساليب تعزيز السلوك وتقنياتها. التعزيز: هو تقديم مثير إيجابي محبب أو إزالة مثير سلبي مؤلم بعد السلوك المرغوب فيه مباشرة، مما يزيد من احتمالية تكرار القيام بالسلوك في المستقبل. أنواع التعزيز: مادي (حلوى، هدايا)، معنوي (ثناء، تصفيق)، رمزي (نجوم، شهادات). القيم التسع المستهدفة في البرنامج مستمدة من برنامج تنمية القدرات البشرية 2021.', 'برنامج تعزيز السلوك الإيجابي - وزارة التعليم 1445هـ'),

-- التوجيه المهني (Career Guidance)
('دليل التوجيه المهني', 'أكاديمية',
'دليل التوجيه المهني صادر عن الإدارة العامة للتوجيه والإرشاد بوزارة التعليم 1444هـ. يهدف إلى تطوير الوعي الذاتي والثقة بالنفس لدى الطلاب، تنمية الوعي المهني، غرس القيم، تطوير السلوك الاجتماعي. يغطي الدليل المراحل الابتدائية والمتوسطة والثانوية. المرحلة الابتدائية: الوعي الذاتي والثقة بالنفس، الوعي المهني، غرس القيم، السلوك الاجتماعي. المرحلة المتوسطة: إدارة الوقت، التواصل الفعال، اتخاذ القرار، المهارات الرقمية، القيم المهنية. المرحلة الثانوية: تخطيط المسار المهني، استكشاف الفرص، بناء المهارات القيادية.', 'دليل التوجيه المهني - وزارة التعليم 1444هـ'),

-- الاستخدام الآمن للإنترنت (Safe Internet Use)
('الاستخدام الآمن للإنترنت والألعاب الإلكترونية', 'إدارية',
'دليل الاستخدام الآمن للإنترنت والألعاب الإلكترونية - الإصدار الرابع 1446هـ/2024م من وزارة التعليم. يتناول مخاطر الإنترنت والألعاب الإلكترونية على الطلبة، أساليب الحماية والوقاية، دور الأسرة والمدرسة في التوعية. يشمل: مفاهيم الأمن السيبراني، تصنيف الألعاب الإلكترونية، مخاطر الاستخدام غير الآمن، إرشادات للاستخدام الآمن، القيم الأخلاقية في الفضاء الرقمي، أدوار ذوي العلاقة في المتابعة والإشراف.', 'دليل الاستخدام الآمن للإنترنت - وزارة التعليم 1446هـ'),

-- الإسعافات الأولية (First Aid)
('دليل الإسعافات الأولية المدرسية', 'مرافق وتجهيزات',
'دليل الإسعافات الأولية صادر عن وزارة الصحة ووزارة التعليم. يتضمن إرشادات للتعامل مع: إسعاف الغريق، إسعاف المصاب بانخماض السكري، إسعاف المصاب بنوبة الصرع، الإسعاف الأولي عند الغصة، الإسعاف الأولي للرعاف. يجب على المدارس توفير صندوق إسعافات أولية مجهز وتدريب المنسوبين على أساسيات الإسعافات الأولية.', 'دليل الإسعافات الأولية - وزارة الصحة/التعليم'),

-- التعامل مع الحالات الطارئة (Emergency Cases)
('دليل التعامل مع الحالات الطارئة', 'مرافق وتجهيزات',
'دليل التعامل مع الحالات الطارئة صادر عن هيئة الصحة العامة السعودية. يتضمن إرشادات للتعامل مع الحالات الطارئة في البيئة المدرسية وكيفية الاتصال بالجهات المختصة (997). يغطي حالات الطوارئ المختلفة والإجراءات الواجب اتباعها، والإنعاش القلبي الرئوي CPR.', 'دليل التعامل مع الحالات الطارئة - هيئة الصحة العامة'),

-- تقويم الطالب (Student Assessment)
('الإجراءات التنفيذية للائحة تقويم الطالب 2025', 'أكاديمية',
'الإجراءات التنفيذية للائحة تقويم الطالب في التعليم العام 2025م. تسعى وزارة التعليم في المملكة العربية السعودية إلى تطوير نظام تقويم شامل يتكامل أساليبه وأدواته وآليات تطبيقه بما يحقق أهداف العملية التعليمية. القواعد: تقويم رياض الأطفال، تقويم الصفين الأول والثاني الابتدائي، تقويم من الصف الثالث الابتدائي إلى الصف السادس، تقويم المرحلة الثانوية، حساب المعدل والتقدير العام، التقويم في التعليم الإلكتروني والتعلم عن بعد، تقويم الطلاب ذوي الإعاقة.', 'الإجراءات التنفيذية للائحة تقويم الطالب 2025 - وزارة التعليم'),

-- عامة (General wellbeing)
('الدعم النفسي والرفاه الطلابي', 'نفسية',
'إرشادات الدعم النفسي من أدلة وزارة التعليم: المنهج الإنمائي يهدف إلى تنمية قدرات الطلاب وزيادة كفاءاتهم وتوجيه نموهم التوجيه السليم. المنهج الوقائي يهدف إلى وقاية الطلاب من الوقوع في المشكلات وتبصيرهم بأفضل الطرق للابتعاد عنها. ثلاث درجات من الوقاية: الأولى (منع الحدوث)، الثانية (الكشف المبكر)، الثالثة (تقليل الآثار السلبية). المنهج العلاجي يهدف إلى مساعدة الطالب على علاج مشكلاته والعودة إلى حالة التوافق والصحة. يجب مراعاة: سرية المعلومات، الالتزام بأخلاقيات المهنة، عدم التسرع في الحكم على سلوك الطلاب، الإحالة للمختصين عند خروج المشكلة عن حدود إمكانات الموجه الطلابي.', 'دليل التدخلات التربوية - وزارة التعليم 1445هـ'),

('المهارات الاجتماعية والتوافق النفسي', 'اجتماعية',
'المهارات الاجتماعية من دليل التدخلات التربوية: تنمية مهارات التواصل الفعال مع الآخرين، بناء علاقات إيجابية مع الأقران والمعلمين، تعزيز الثقة بالنفس وتأكيد الذات، تعلم مهارات حل المشكلات وإدارة الانفعالات. من برنامج تعزيز السلوك الإيجابي: غرس قيم الاحترام والتسامح والتعاون، تنمية المسؤولية الاجتماعية لدى الطلاب، تعزيز السلوك الإيجابي من خلال بيئة محفزة وجاذبة. من برنامج رفق: التأكيد على تعاليم الشريعة الإسلامية في التعامل بالحسنى والتسامح والرحمة، تهيئة بيئة مدرسية آمنة خالية من العنف.', 'أدلة وزارة التعليم المتعددة');
